-- REGA REGA BATUMI — 13 real apartments (EN+RU), self-hosted photos /public/apartments/. Idempotent.
alter table apartments add column if not exists title_ru text;
alter table apartments add column if not exists summary_ru text;
alter table apartments add column if not exists beds int;
alter table apartments add column if not exists baths int;
alter table apartments add column if not exists rooms jsonb default '[]'::jsonb;
alter table apartments add column if not exists airbnb_id text;
delete from apartments where photos::text like '%picsum%';
delete from apartments where slug = 'alliance-studio-12th-floor';
insert into apartments
  (operator_id, city_id, slug, title, title_ru, status, summary, summary_ru,
   lat, lng, bedrooms, beds, baths, max_guests, price_from, photos, amenities, rooms, airbnb_id)
select o.id, c.id, v.slug, v.title, v.title_ru, 'published', v.summary, v.summary_ru,
   v.lat, v.lng, v.bedrooms, v.beds, v.baths, v.guests, null,
   v.photos, v.amenities, v.rooms, v.airbnb_id
from operators o, cities c, (values
  ('sunset-apartment', 'Sunset Apartment', 'Квартира Sunset', 'Sunset Apartment — a stylish seaside stay designed for comfort. 
Just 1 minute to the beach — the sea is right next to you, visible and felt in every moment. Fully equipped with everything you need: a cozy bed, washing machine, dishwasher, beautiful tableware, essential toiletries, a full kitchen, and floor heating.
The highlight is a spacious terrace with stunning sunset views — perfect for breakfast, dinner, and soaking in the seaside atmosphere.', 'Sunset Apartment — стильное пространство у моря для комфортного отдыха. 
Всего 1 минута до пляжа, море буквально рядом — его видно и ощущается в каждом моменте.
Апартаменты полностью укомплектованы: удобная кровать, посудомоечная и стиральная машины, красивая посуда, базовые средства гигиены, полноценная кухня и тёплый пол.
Главная особенность — просторная терраса с видами и закатами Батуми. Идеально для завтраков, ужинов и отдыха в атмосфере города и моря 🌊', 41.6349, 41.6074, 1, 2, 1, 4, '["/apartments/sunset-apartment/01.jpg", "/apartments/sunset-apartment/02.jpg", "/apartments/sunset-apartment/03.jpg", "/apartments/sunset-apartment/04.jpg", "/apartments/sunset-apartment/05.jpg", "/apartments/sunset-apartment/06.jpg", "/apartments/sunset-apartment/07.jpg", "/apartments/sunset-apartment/08.jpg", "/apartments/sunset-apartment/09.jpg", "/apartments/sunset-apartment/10.jpg", "/apartments/sunset-apartment/11.jpg", "/apartments/sunset-apartment/12.jpg", "/apartments/sunset-apartment/13.jpg", "/apartments/sunset-apartment/14.jpg", "/apartments/sunset-apartment/15.jpg", "/apartments/sunset-apartment/16.jpg", "/apartments/sunset-apartment/17.jpg", "/apartments/sunset-apartment/18.jpg", "/apartments/sunset-apartment/19.jpg", "/apartments/sunset-apartment/20.jpg", "/apartments/sunset-apartment/21.jpg", "/apartments/sunset-apartment/22.jpg", "/apartments/sunset-apartment/23.jpg", "/apartments/sunset-apartment/24.jpg", "/apartments/sunset-apartment/25.jpg", "/apartments/sunset-apartment/26.jpg", "/apartments/sunset-apartment/27.jpg", "/apartments/sunset-apartment/28.jpg", "/apartments/sunset-apartment/29.jpg", "/apartments/sunset-apartment/30.jpg", "/apartments/sunset-apartment/31.jpg", "/apartments/sunset-apartment/32.jpg", "/apartments/sunset-apartment/33.jpg", "/apartments/sunset-apartment/34.jpg", "/apartments/sunset-apartment/35.jpg", "/apartments/sunset-apartment/36.jpg", "/apartments/sunset-apartment/37.jpg", "/apartments/sunset-apartment/38.jpg", "/apartments/sunset-apartment/39.jpg", "/apartments/sunset-apartment/40.jpg", "/apartments/sunset-apartment/41.jpg", "/apartments/sunset-apartment/42.jpg", "/apartments/sunset-apartment/43.jpg", "/apartments/sunset-apartment/44.jpg", "/apartments/sunset-apartment/45.jpg", "/apartments/sunset-apartment/46.jpg", "/apartments/sunset-apartment/47.jp