where o.slug='bre' and c.slug='batumi'
on conflict (slug) do update set
  title=excluded.title, title_ru=excluded.title_ru, summary=excluded.summary, summary_ru=excluded.summary_ru,
  lat=excluded.lat, lng=excluded.lng, bedrooms=excluded.bedrooms, beds=excluded.beds, baths=excluded.baths,
  max_guests=excluded.max_guests, photos=excluded.photos, amenities=excluded.amenities,
  rooms=excluded.rooms, airbnb_id=excluded.airbnb_id, status='published';
drop view if exists apartments_public;
create view apartments_public as
  select id, operator_id, city_id, slug, title, title_ru, summary, summary_ru,
         neighborhood, lat, lng, bedrooms, beds, baths, max_guests, price_from,
         photos, amenities, rooms
  from apartments where status='published';
grant select on apartments_public to anon;
